noncompliant:
// Using memcmp with non-trivial types
struct Person {
  char name[32];
  int age;
  // Padding may exist here
};

struct Person p1 = {"John", 25};
struct Person p2 = {"John", 25};

// Non-compliant: struct may have padding
if (memcmp(&p1, &p2, sizeof(struct Person)) == 0) {
  printf("Equal");
}

// Non-compliant: comparing arrays of structs
struct Person people1[2], people2[2];
memcmp(people1, people2, sizeof(people1));

compliant:
// Use memcmp only with simple types
char buffer1[256];
char buffer2[256];

// Compliant: comparing plain char arrays
if (memcmp(buffer1, buffer2, 256) == 0) {
  printf("Buffers are equal");
}

// For structs, compare fields individually
struct Person {
  char name[32];
  int age;
};

bool persons_equal(const struct Person* p1, const struct Person* p2) {
  return strcmp(p1->name, p2->name) == 0 && p1->age == p2->age;
}

// Or use explicit comparison
int compare_simple_arrays(int* arr1, int* arr2, size_t count) {
  for (size_t i = 0; i < count; i++) {
    if (arr1[i] != arr2[i]) return arr1[i] - arr2[i];
  }
  return 0;
}
